import { useState } from "react";
import { useNavigate } from "react-router-dom";

const AddExpense = () => {
    const [splitType, setSplitType] = useState("equal");
    const navigate = useNavigate();

    // simple dummy data
    const groups = ["Trip", "Roommates"];
    const members = ["You", "Alex", "Sam"];

    const handleSubmit = (e) => {
        e.preventDefault();
        navigate("/dashboard"); // go back after submit
    };

    return (
        <div className="page">
            <h1 className="page-title">Add Expense</h1>
            <p className="page-sub">
                Record a new shared expense and split it instantly.
            </p>

            <div className="card-soft">
                <form onSubmit={handleSubmit}>

                    {/* GROUP */}
                    <div className="form-group">
                        <label className="form-label-upper">SELECT GROUP</label>
                        <select className="form-select">
                            {groups.map((g) => (
                                <option key={g}>{g}</option>
                            ))}
                        </select>
                    </div>

                    {/* DESCRIPTION + AMOUNT */}
                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20 }}>
                        <div className="form-group">
                            <label className="form-label-upper">DESCRIPTION</label>
                            <input className="form-input" placeholder="Coffee, dinner..." />
                        </div>

                        <div className="form-group">
                            <label className="form-label-upper">AMOUNT</label>
                            <input className="form-input" placeholder="₹ 0.00" />
                        </div>
                    </div>

                    {/* PAID BY + CATEGORY */}
                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20 }}>
                        <div className="form-group">
                            <label className="form-label-upper">PAID BY</label>
                            <select className="form-select">
                                {members.map((m) => (
                                    <option key={m}>{m}</option>
                                ))}
                            </select>
                        </div>

                        <div className="form-group">
                            <label className="form-label-upper">CATEGORY</label>
                            <select className="form-select">
                                <option>Food</option>
                                <option>Travel</option>
                                <option>Shopping</option>
                            </select>
                        </div>
                    </div>

                    {/* SPLIT TYPE */}
                    <div className="form-group">
                        <label className="form-label-upper">SPLIT METHOD</label>
                        <div className="split-options">
                            {["equal", "custom", "percentage"].map((type) => (
                                <button
                                    type="button"
                                    key={type}
                                    className={`split-option ${splitType === type ? "active" : ""
                                        }`}
                                    onClick={() => setSplitType(type)}
                                >
                                    {type}
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* MEMBERS */}
                    <div className="split-members-list">
                        {members.map((m, i) => (
                            <div key={i} className="split-member-item">
                                <span>{m}</span>
                                <span>₹0.00 ✓</span>
                            </div>
                        ))}
                    </div>

                    {/* SUBMIT */}
                    <button className="form-submit">Post Expense</button>
                </form>
            </div>
        </div>
    );
};

export default AddExpense;
